import React, { useState, useEffect } from 'react';
import axios from 'axios';
import EmployeeLayout from '../components/EmployeeLayout';
import styles from './TestCardPage.module.css';

function TestCardPage() {
  const [books, setBooks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchBooks = async () => {
      try {
        const userInfo = JSON.parse(localStorage.getItem('userInfo'));
        const config = {
          headers: {
            Authorization: `Bearer ${userInfo.token}`,
          },
        };
        const { data } = await axios.get('/api/books', config);
        setBooks(data);
      } catch (err) {
        setError(err.response?.data?.message || 'Failed to fetch books');
      } finally {
        setLoading(false);
      }
    };

    fetchBooks();
  }, []);

  if (loading) {
    return <EmployeeLayout title="Test Cards"><div>Loading...</div></EmployeeLayout>;
  }

  if (error) {
    return <EmployeeLayout title="Test Cards"><p style={{color: 'red'}}>{error}</p></EmployeeLayout>;
  }

  return (
    <EmployeeLayout title="Book Test Cards">
      <div className={styles.cardContainer}>
        {books.map((book) => (
          <div key={book._id} className={styles.bookCard}>
            <h2>{book.seriesTitle} #{book.issueNumber}</h2>
            <img src={book.coverArt || '/images/cover-placeholder.png'} alt={`${book.seriesTitle} #${book.issueNumber}`} className={styles.coverArt} />
            <p><strong>Publisher:</strong> {book.publisher || 'N/A'}</p>
            <p><strong>Release Date:</strong> {new Date(book.releaseDate).toLocaleDateString()}</p>
          </div>
        ))}
      </div>
    </EmployeeLayout>
  );
}

export default TestCardPage;
